"const fs = require('fs');
const readline = require('readline');
const path = 'C:\\Users\\GAMER\\.gemini\\antigravity-ide\\brain\\52165ffc-f10d-4bd1-ab8b-e689cbe8014b\\.system_generated\\logs\\transcript.jsonl';

const rl = readline.createInterface({
    input: fs.createReadStream(path),
    crlfDelay: Infinity
});

let matches = [];

rl.on('line', (line) => {
    if (line.includes('makaleler-data.js') && line.includes('Pasif Gelir Kaynakları')) {
        matches.push(line);
    }
});

rl.on('close', () => {
    if (matches.length > 0) {
        // Just save the last match's tool_calls to a file to inspect it
        try {
            const obj = JSON.parse(matches[matches.length - 1]);
            fs.writeFileSync('recovered.json', JSON.stringify(obj.tool_calls, null, 2));
            console.log('Saved to recovered.json');
        } catch(e) {
            console.log('Failed to parse json');
        }
    } else {
        console.log('No matches found.');
    }
});
"
